from dataclasses import dataclass, field
from datetime import date, timedelta
from enum import Enum

class TrackType(Enum):
    PRODUCT      = "product"      # standard PI committed scope
    ML_SPIKE     = "ml_spike"     # experimental; uncommitted
    PLATFORM     = "platform"     # infra and tooling
    INTEGRATION  = "integration"  # cross-track convergence work

@dataclass
class PIObjective:
    title: str
    track: TrackType
    committed: bool           # False for ML spike objectives
    team: str
    business_value: int       # 1-10 SAFe BV score (0 for spikes)
    dependencies: list[str] = field(default_factory=list)

@dataclass
class ProgramIncrement:
    number: int
    start_date: date
    end_date: date            # typically start + 70 days (10 weeks)
    objectives: list[PIObjective] = field(default_factory=list)
    ml_eval_checkpoint: date = None   # when model eval results are expected

    @property
    def duration_weeks(self) -> int:
        return (self.end_date - self.start_date).days // 7

    def committed_objectives(self) -> list[PIObjective]:
        return [o for o in self.objectives if o.committed]

    def spike_objectives(self) -> list[PIObjective]:
        return [o for o in self.objectives if not o.committed]

    def ml_capacity_pct(self) -> float:
        ml = sum(1 for o in self.objectives if o.track == TrackType.ML_SPIKE)
        total = len(self.objectives)
        return ml / total * 100 if total else 0.0

    def validate_ml_capacity(self, max_pct: float = 30.0) -> list[str]:
        errors = []
        pct = self.ml_capacity_pct()
        if pct > max_pct:
            errors.append(
                f"ML spike capacity is {pct:.0f}% — exceeds recommended {max_pct:.0f}% cap"
            )
        return errors

from dataclasses import dataclass, field
from enum import Enum
from typing import Optional

class BacklogLane(Enum):
    PRODUCT    = "product"
    ML_EXPERIMENT = "ml_experiment"
    PLATFORM   = "platform"

@dataclass
class MLExperimentItem:
    """
    A backlog item representing a time-boxed ML experiment.
    Tracked differently from product stories: no story points,
    costs are compute + eng days, success is a binary hypothesis test.
    """
    id: str
    title: str
    hypothesis: str                 # what we expect to learn
    success_criterion: str          # how we know the experiment succeeded
    max_duration_days: int          # time-box (fail fast)
    compute_budget_gbp: float
    eng_days: float
    lane: BacklogLane = BacklogLane.ML_EXPERIMENT
    result: Optional[str] = None    # "confirmed" | "rejected" | "inconclusive"
    result_date: Optional[str] = None

    def is_complete(self) -> bool:
        return self.result is not None

    def feeds_pi_planning(self) -> bool:
        """
        Completed experiments inform the next PI's committed objectives.
        Inconclusive ones may need a follow-up spike.
        """
        return self.result in ("confirmed", "rejected")


@dataclass
class DualLaneBacklog:
    product_items: list[dict]            # standard user stories
    ml_items: list[MLExperimentItem]     # experiment items
    ordering_weights: dict = field(default_factory=lambda: {
        "product": 0.7,    # 70% of sprint capacity to product lane by default
        "ml": 0.3,         # 30% to ML experimentation
    })

    def pending_experiments(self) -> list[MLExperimentItem]:
        return [i for i in self.ml_items if not i.is_complete()]

    def completed_experiments(self) -> list[MLExperimentItem]:
        return [i for i in self.ml_items if i.is_complete()]

    def total_compute_budget(self) -> float:
        return sum(i.compute_budget_gbp for i in self.pending_experiments())

from dataclasses import dataclass, field
from enum import Enum

class ObjectiveType(Enum):
    COMMITTED = "committed"
    SPIKE     = "spike"
    STRETCH   = "stretch"

@dataclass
class PIObjectiveWithConfidence:
    title: str
    team: str
    objective_type: ObjectiveType
    business_value: int           # 0-10 (0 for spikes)
    confidence_votes: list[int]   # each team member's fist-of-five vote (1-5)
    compute_hours_allocated: float = 0.0   # GPU hours budgeted for this objective

    @property
    def average_confidence(self) -> float:
        return sum(self.confidence_votes) / len(self.confidence_votes) if self.confidence_votes else 0.0

    @property
    def confidence_threshold(self) -> float:
        """Committed objectives require ≥3.0; spikes require ≥2.0."""
        return 3.0 if self.objective_type == ObjectiveType.COMMITTED else 2.0

    def passes_confidence_gate(self) -> bool:
        return self.average_confidence >= self.confidence_threshold

    def risk_flag(self) -> str:
        avg = self.average_confidence
        if avg < self.confidence_threshold:
            return f"LOW CONFIDENCE: {avg:.1f} < threshold {self.confidence_threshold}"
        if avg < self.confidence_threshold + 0.5:
            return f"MARGINAL: {avg:.1f} — review dependencies"
        return "OK"


@dataclass
class PIComputeBudget:
    total_gpu_hours: float
    allocations: dict[str, float]   # team → allocated GPU hours

    def remaining(self) -> float:
        return self.total_gpu_hours - sum(self.allocations.values())

    def validate(self) -> list[str]:
        errors = []
        if self.remaining() < 0:
            errors.append(
                f"Compute over-allocated by {abs(self.remaining()):.0f} hours"
            )
        return errors


def run_pi_confidence_vote(
    objectives: list[PIObjectiveWithConfidence],
    compute_budget: PIComputeBudget,
) -> dict:
    """
    Run the PI planning confidence check for a GenAI programme.
    Returns a summary dict with low-confidence items and budget status.
    """
    low_confidence = [o for o in objectives if not o.passes_confidence_gate()]
    return {
        "total_objectives": len(objectives),
        "low_confidence_count": len(low_confidence),
        "low_confidence_items": [(o.title, o.risk_flag()) for o in low_confidence],
        "compute_remaining_hours": compute_budget.remaining(),
        "compute_validation": compute_budget.validate(),
        "ready_to_commit": len(low_confidence) == 0 and not compute_budget.validate(),
    }
